663	        () => fix.cartograph.showPiece('w-missing'),
664	        /not found/,
665	      );
666	    });
667	  });
668	
669	  // ── Lifecycle coupling ────────────────────────────────────────────
670	
671	  describe('lifecycle coupling — transitionX', () => {
672	    it('vision: writ.phase and doc.stage move in lockstep', async () => {
673	      const vision = await fix.cartograph.createVision({ title: 'V', body: 'B' });
674	      // Walk new → open → completed (terminal).
675	      const afterOpen = await fix.cartograph.transitionVision(vision.id, {
676	        phase: 'open',
677	        stage: 'active',
678	      });
679	      assert.equal(afterOpen.stage, 'active');
680	      const visionWrit1 = await fix.clerk.show(vision.id);
681	      assert.equal(visionWrit1.phase, 'open');
682	
683	      const afterDone = await fix.cartograph.transitionVision(vision.id, {
684	        phase: 'completed',
685	        stage: 'sunset',
686	        resolution: 'patron retired the vision',
687	      });
688	      assert.equal(afterDone.stage, 'sunset');
689	
690	      const visionWrit2 = await fix.clerk.show(vision.id);
691	      assert.equal(visionWrit2.phase, 'completed');
692	      assert.equal(visionWrit2.resolution, 'patron retired the vision');
693	      assert.ok(visionWrit2.resolvedAt, 'terminal transition stamps resolvedAt');
694	    });
695	
696	    it('charge: writ.phase and doc.stage move in lockstep through validated', async () => {
697	      const vision = await fix.cartograph.createVision({ title: 'V', body: 'B' });
698	      const charge = await fix.cartograph.createCharge({
699	        parentId: vision.id,
700	        title: 'C',
701	        body: 'B',
702	      });
703	
704	      await fix.cartograph.transitionCharge(charge.id, {
705	        phase: 'open',
706	        stage: 'active',
707	      });
708	      const afterValidated = await fix.cartograph.transitionCharge(charge.id, {
709	        phase: 'completed',
710	        stage: 'validated',
711	      });
712	      assert.equal(afterValidated.stage, 'validated');
713	
714	      const chargeWrit = await fix.clerk.show(charge.id);
715	      assert.equal(chargeWrit.phase, 'completed');
716	    });
717	
718	    it('piece: writ.phase and doc.stage move in lockstep through done', async () => {
719	      const vision = await fix.cartograph.createVision({ title: 'V', body: 'B' });
720	      const charge = await fix.cartograph.createCharge({
721	        parentId: vision.id,
722	        title: 'C',
723	        body: 'B',
724	      });
725	      const piece = await fix.cartograph.createPiece({
726	        parentId: charge.id,
727	        title: 'P',
728	        body: 'B',
729	      });
730	
731	      await fix.cartograph.transitionPiece(piece.id, {
732	        phase: 'open',
733	        stage: 'active',
734	      });
735	      const afterDone = await fix.cartograph.transitionPiece(piece.id, {
736	        phase: 'completed',
737	        stage: 'done',
738	      });
739	      assert.equal(afterDone.stage, 'done');
740	
741	      const pieceWrit = await fix.clerk.show(piece.id);
742	      assert.equal(pieceWrit.phase, 'completed');
743	    });
744	
745	    it('rejects an illegal phase transition without touching the companion doc', async () => {
746	      const vision = await fix.cartograph.createVision({ title: 'V', body: 'B' });
747	
748	      // new → completed is not a legal direct edge for the mandate-clone
749	      // machine; the typed API must reject and the doc's stage must
750	      // remain at draft.
751	      await assert.rejects(
752	        () =>
753	          fix.cartograph.transitionVision(vision.id, {
754	            phase: 'completed',
755	            stage: 'sunset',
756	          }),
757	        (err: Error) => {
758	          assert.match(err.message, /transition/i);
759	          return true;
760	        },
761	      );
762	
763	      const after = await fix.cartograph.showVision(vision.id);
764	      assert.equal(after.stage, 'draft', 'failed transition must not move the stage');
765	
766	      const writ: WritDoc = await fix.clerk.show(vision.id);
767	      assert.equal(writ.phase, 'new', 'failed transition must not move the writ phase');
768	    });
769	
770	    it('rolls back both writes when the transition fails', async () => {
771	      const vision = await fix.cartograph.createVision({ title: 'V', body: 'B' });
772	      // Move to open so a subsequent failed transition leaves the writ
773	      // in `open`, not `new`.
774	      await fix.cartograph.transitionVision(vision.id, {
775	        phase: 'open',
776	        stage: 'active',
777	      });
778	
779	      // Drive the writ to completed via Clerk directly (no doc patch).
780	      // Then attempt a typed-API transition that the writ rejects
781	      // (terminal → anything). Both writ.phase and doc.stage must end
782	      // unchanged.
783	      await fix.clerk.transition(vision.id, 'completed');
784	
785	      await assert.rejects(
786	        () =>
787	          fix.cartograph.transitionVision(vision.id, {
788	            phase: 'open',
789	            stage: 'active',
790	          }),
791	        /transition/i,
792	      );
793	
794	      const docAfter = await fix.cartograph.showVision(vision.id);
795	      // The companion doc stage was last set to 'active'; it must NOT
796	      // have been touched by the failed transition.
797	      assert.equal(
798	        docAfter.stage,
799	        'active',
800	        'failed transition rolls back the companion doc patch',
801	      );
802	    });
803	  });
804	
805	  // ── Codex inheritance ─────────────────────────────────────────────
806	
807	  describe('codex inheritance', () => {
808	    it('charge inherits the parent vision codex when not explicitly supplied', async () => {
809	      const vision = await fix.cartograph.createVision({
810	        title: 'V',
811	        body: 'B',
812	        codex: 'inherited',
813	      });
814	      const charge = await fix.cartograph.createCharge({
815	        parentId: vision.id,
816	        title: 'C',
817	        body: 'B',
818	      });
819	      assert.equal(charge.codex, 'inherited');
820	
821	      const chargeWrit = await fix.clerk.show(charge.id);
822	      assert.equal(chargeWrit.codex, 'inherited');
823	    });
824	
825	    it('an explicit codex on createCharge overrides parent inheritance', async () => {
826	      const vision = await fix.cartograph.createVision({
827	        title: 'V',
828	        body: 'B',
829	        codex: 'parent-codex',
830	      });
831	      const charge = await fix.cartograph.createCharge({
832	        parentId: vision.id,
833	        title: 'C',
834	        body: 'B',
835	        codex: 'override',
836	      });
837	      assert.equal(charge.codex, 'override');
838	    });
839	
840	    it('piece inherits codex through nested ancestors', async () => {
841	      const vision = await fix.cartograph.createVision({
842	        title: 'V',
843	        body: 'B',
844	        codex: 'main',
845	      });
846	      const charge = await fix.cartograph.createCharge({
847	        parentId: vision.id,
848	        title: 'C',
849	        body: 'B',
850	      });
851	      const p1 = await fix.cartograph.createPiece({
852	        parentId: charge.id,
853	        title: 'P1',
854	        body: 'B',
855	      });
856	      const p2 = await fix.cartograph.createPiece({
857	        parentId: p1.id,
858	        title: 'P2',
859	        body: 'B',
860	      });
861	      assert.equal(p2.codex, 'main', 'piece codex inherits through nested chain');
862	    });
863	  });
864	
865	  // ── Companion-book separation ─────────────────────────────────────
866	
867	  describe('companion-book separation', () => {
868	    it('keeps each book scoped to its own type — no cross-pollination', async () => {
869	      const vision = await fix.cartograph.createVision({ title: 'V', body: 'B' });
870	      const charge = await fix.cartograph.createCharge({
871	        parentId: vision.id,
872	        title: 'C',
873	        body: 'B',
874	      });
875	      const piece = await fix.cartograph.createPiece({
876	        parentId: charge.id,
877	        title: 'P',
878	        body: 'B',
879	      });
880	
881	      // Each list returns only its own type's docs.
882	      const visions = await fix.cartograph.listVisions();
883	      assert.equal(visions.length, 1);
884	      assert.equal(visions[0].id, vision.id);
885	
886	      const charges = await fix.cartograph.listCharges();
887	      assert.equal(charges.length, 1);
888	      assert.equal(charges[0].id, charge.id);
889	
890	      const pieces = await fix.cartograph.listPieces();
891	      assert.equal(pieces.length, 1);
892	      assert.equal(pieces[0].id, piece.id);
893	    });
894	
895	    it('typed show methods do not retrieve docs from the wrong book', async () => {
896	      const vision = await fix.cartograph.createVision({ title: 'V', body: 'B' });
897	      // showCharge on a vision id finds nothing — book separation.
898	      await assert.rejects(
899	        () => fix.cartograph.showCharge(vision.id),
900	        /not found/,
901	      );
902	      await assert.rejects(
903	        () => fix.cartograph.showPiece(vision.id),
904	        /not found/,
905	      );
906	    });
907	  });
908	
909	  // ── Apparatus shape ───────────────────────────────────────────────
910	
911	  describe('apparatus shape', () => {
912	    it('declares requires: ["stacks", "clerk"] and recommends: ["oculus"]', () => {
913	      const plugin = createCartograph();
914	      const apparatus =
915	        (plugin as { apparatus: { requires?: string[]; recommends?: string[] } }).apparatus;
916	      assert.deepEqual(apparatus.requires, ['stacks', 'clerk']);
917	      assert.deepEqual(apparatus.recommends, ['oculus']);
