      );
    }

    const prev = JSON.parse(existing.content) as BookEntry;
    const updated = { ...prev, ...fields, id } as BookEntry;
    const json = JSON.stringify(updated);

    this.db
      .prepare(`UPDATE "${table}" SET content = ? WHERE id = ?`)
      .run(json, id);

