    return fn(txCtx);
  }
  // Start new transaction...
}
```

Key consequence: calling `clerk.transition()` (which calls `writs.patch()`) or `clerk.setWritExt()` (which calls `stacks.transaction()` internally) from inside an outer `stacks.transaction` flattens into the outer transaction. This is the mechanism that makes the brief's prescribed pattern work.

**`Book.find(query)` with dot-notation fields:**

```typescript
// query.ts SAFE_FIELD_RE = /^[A-Za-z0-9_.-]+/  ← dots allowed
// sqlite-backend.ts: toJsonPath('ext.cartograph.stage') → '$.ext.cartograph.stage'
// → json_extract(content, '$.ext.cartograph.stage')
```

So `['ext.cartograph.stage', '=', 'active']` is a valid WhereCondition on the writs book. Works without an index (full scan) but correct.

**`Book.doPut/doPatch` auto-wrapping:**

```typescript
async doPut(ref, entry) {
  if (!this.activeTx) return this.runTransaction(async () => this.doPutInTx(ref, entry));
  return this.doPutInTx(ref, entry);
}
```

Writes auto-wrap in a transaction if no active one exists, or join the active one.

### Clerk API — relevant primitives

**`clerk.transition(id, to, fields?)` — does NOT wrap in stacks.transaction:**

Directly calls `writs.patch(id, patch)` which auto-wraps or joins active tx. Strips `ext` and `status` from `fields` — cannot smuggle `ext` updates through transition.

**`clerk.setWritExt(writId, pluginId, value)` — wraps in stacks.transaction:**

```typescript
// Read-modify-write:
return stacks.transaction(async (tx) => {
  const txWrits = tx.book<WritDoc>('clerk', 'writs');
  const existing = await txWrits.get(writId);
  const prevExt = (existing.ext ?? {}) as Record<string, unknown>;
  const nextExt = { ...prevExt, [pluginId]: value };
  return txWrits.patch(writId, { ext: nextExt, updatedAt: new Date().toISOString() });
});
```

When called from inside an outer `stacks.transaction`, the inner `stacks.transaction()` call flattens — both reads and writes happen in the outer transaction.

**`clerk.edit({ id, title?, body?, codex? })` — patches writ title/body/codex.** Available for codex updates in patchX.

**`clerk.list(filters?)` — supports `type` and `codex` filtering via `writ.type`/`writ.codex` indexes.** Does NOT support `ext.cartograph.stage` filtering. The cartograph will query the writs book directly for full filter support.

### Writs book current indexes:

```
['phase', 'type', 'createdAt', 'parentId', ['phase', 'type'], ['phase', 'createdAt'], ['parentId', 'phase']]
```

No index on `ext.cartograph.stage`. Filtering by stage works (JSON path query) but as a full table scan.

